import React from "react";
import ExpertForm from "../components/ExpertForm";
import ExpertList from "../components/ExpertList";

const Home = () => {
  return (
    <div>
      <div className="card">
        <h2>Add Expert</h2>
        <ExpertForm />
      </div>

      <div className="card">
        <h2>Experts</h2>
        <ExpertList />
      </div>
    </div>
  );
};

export default Home;
